"""medical-order-agent agent — generated by transpiler.

NOTE (adk web / adk run dev-server):
    The `root_agent` module-level variable is kept for `adk web` / `adk run`
    dev-server discovery. It is initialised with correlation_id="boot" — not
    for production use. Production callers use _build_agent(correlation_id).
    The ADK service name convention uses hyphens; Python module uses underscores.
"""

from __future__ import annotations

import logging
import os

from urllib.parse import urlparse

import httpx
from collections.abc import Callable
from typing import Any

from google.adk.agents import LlmAgent
from google.adk.tools.base_tool import BaseTool
from google.adk.tools.base_toolset import BaseToolset
from google.adk.tools.mcp_tool import McpToolset
from google.adk.tools.mcp_tool.mcp_session_manager import SseConnectionParams
from google.adk.tools.openapi_tool.openapi_spec_parser.openapi_toolset import OpenAPIToolset
from security import make_pii_callback

_LOGGER = logging.getLogger(__name__)

_ToolItem = Callable[..., Any] | BaseTool | BaseToolset

_SSE_HEADERS: dict[str, str] = {
    "Accept": "application/json, text/event-stream",
}

_scheduling_openapi_url: str = os.environ.get(
    "SCHEDULING_OPENAPI_URL",
    "http://scheduling-api:8000/openapi.json",
)

# ADR-0009: fetch timeout tunable via env without regenerating the agent.
_scheduling_fetch_timeout_seconds: float = float(
    os.environ.get(
        "SCHEDULING_OPENAPI_FETCH_TIMEOUT_SECONDS",
        "10",
    )
)


def _load_scheduling_toolset(correlation_id: str) -> "OpenAPIToolset":
    """Fetch OpenAPI spec for scheduling and return a toolset.

    ADK real-world: OpenAPIToolset requires spec_dict, not spec_url.
    X-Correlation-ID is sent on the spec-fetch call only; OpenAPIToolset does
    not natively propagate headers to individual tool invocations (ADK limitation).

    Args:
        correlation_id: UUID to include in the spec-fetch request header.

    Returns:
        OpenAPIToolset initialised with the fetched spec_dict.

    Raises:
        httpx.ConnectError: if the spec URL is unreachable.
        httpx.ConnectTimeout: if the connection times out.
    """
    resp = httpx.get(
        _scheduling_openapi_url,
        timeout=_scheduling_fetch_timeout_seconds,
        headers={"X-Correlation-ID": correlation_id},
    )
    resp.raise_for_status()
    spec_dict = resp.json()
    # FastAPI does not emit a `servers` entry by default; without it the
    # OpenAPIToolset constructs requests with only the path and httpx rejects
    # them with UnsupportedProtocol. Derive the base URL from the spec URL
    # itself so the fix works for any spec that omits `servers`.
    if not spec_dict.get("servers"):
        parsed = urlparse(_scheduling_openapi_url)
        spec_dict["servers"] = [{"url": f"{parsed.scheme}://{parsed.netloc}"}]
    return OpenAPIToolset(spec_dict=spec_dict)


def _build_agent(correlation_id: str) -> LlmAgent:
    """Build and return the LlmAgent wired with all toolsets.

    Constructs McpToolset instances with X-Correlation-ID injected into SSE
    headers so every MCP call is traceable end-to-end (BLOCKER-2).

    Args:
        correlation_id: UUID generated at CLI startup. Injected into all
            outbound SSE and HTTP headers.

    Returns:
        Fully configured LlmAgent ready for Runner.
    """
    _corr_headers = {**_SSE_HEADERS, "X-Correlation-ID": correlation_id}

    ocr_toolset = McpToolset(
        connection_params=SseConnectionParams(
            url=os.environ.get("OCR_MCP_URL", "http://ocr-mcp:8001/sse"),
            headers=_corr_headers,
        ),
        tool_filter=[],  # ADR-0010: server not exposed to the LlmAgent
    )
    rag_toolset = McpToolset(
        connection_params=SseConnectionParams(
            url=os.environ.get("RAG_MCP_URL", "http://rag-mcp:8002/sse"),
            headers=_corr_headers,
        ),
        tool_filter=["search_exam_code", "list_exams"],
    )

    _tools: list[_ToolItem] = [
        ocr_toolset,
        rag_toolset,
    ]
    try:
        scheduling_toolset: "OpenAPIToolset | None" = _load_scheduling_toolset(correlation_id)
    except (httpx.ConnectError, httpx.ConnectTimeout) as exc:
        _LOGGER.warning(
            "scheduling.toolset.unavailable",
            extra={
                "event": "scheduling.toolset.unavailable",
                "correlation_id": correlation_id,
                "error": str(exc),
            },
        )
        scheduling_toolset = None
    if scheduling_toolset is not None:
        _tools.append(scheduling_toolset)

    # ADR-0009: GEMINI_MODEL env overrides spec default at runtime
    return LlmAgent(
        name="medical_order_agent",  # ADK requires valid Python identifier
        model=os.environ.get("GEMINI_MODEL", "gemini-2.5-flash-lite"),
        description="Agente de agendamento de exames a partir de pedidos medicos digitalizados",
        instruction="Voce e um agente de agendamento de exames medicos. Siga o plano abaixo na ordem exata.\n\nPLANO FIXO (plan-then-execute):\n1. Voce recebera um bloco \u0027EXAMES DETECTADOS (OCR pre-executado pelo CLI): \u003cjson-array\u003e\u0027 no prompt. Use essa lista como ponto de partida - o OCR ja foi executado deterministicamente pela CLI (ADR-0010). NAO chame nenhuma ferramenta de OCR. IGNORE itens da lista que comecem com \u0027\u003c\u0027 (placeholders de PII como \u003cLOCATION\u003e, \u003cPERSON\u003e) ou com \u0027[\u0027 (bullets residuais).\n2. Para cada exame restante, chame search_exam_code EM PARALELO (emita multiplas tool calls na mesma resposta).\n3. Monte uma lista interna [(nome, codigo, score)] - NAO formate a saida ainda.\n4. Se search_exam_code retornar null ou score \u003c 0.80: chame list_exams(limit=20) UMA vez, escolha o candidato mais proximo, marque inconclusive=true e prossiga. NAO pergunte ao usuario - nao ha usuario interativo.\n5. Faca UM UNICO POST /api/v1/appointments com todos os exames no campo exams[]. Use patient_ref=\u0027anon-\u003chash\u003e\u0027 (invente um hash curto). REGRA DE DATA: scheduled_for DEVE ser \u003e= hoje + 48 horas (a API rejeita datas passadas ou muito proximas com 422). Se nao souber a data de hoje, use 2027-01-01T09:00:00Z como base segura. Leia appointment_id e scheduled_for da resposta.\n6. SAIDA FINAL: responda APENAS com UM UNICO objeto JSON valido. Schema obrigatorio (discriminado por \u0027status\u0027):\nSUCESSO: {\"status\": \"success\", \"exams\": [{\"name\": \"\u003cnome\u003e\", \"code\": \"\u003ccodigo\u003e\", \"score\": \u003cfloat 0..1\u003e, \"inconclusive\": \u003cbool\u003e}, ...], \"appointment_id\": \"\u003cid retornado pela API\u003e\", \"scheduled_for\": \"\u003cISO-8601 retornado pela API\u003e\"}\nERRO (use quando nao conseguir agendar apos esgotar retries permitidos): {\"status\": \"error\", \"error\": {\"code\": \"\u003cE_*\u003e\", \"message\": \"\u003cdescricao curta\u003e\", \"hint\": \"\u003cacao sugerida ou null\u003e\"}}\nREGRA ABSOLUTA DE FORMATO (critica): NUNCA envolva sua resposta em ```json, em ``` ou em qualquer outro fence markdown. NUNCA adicione texto, prosa ou comentario antes ou depois do JSON. A primeira linha da sua resposta DEVE comecar com \u0027{\u0027 e a ultima linha DEVE terminar com \u0027}\u0027. Qualquer desvio disto faz o parser explodir.\n\nPOLITICA DE ERROS (congelada):\n- E_MCP_TIMEOUT: 1 retry com delay fixo de 500ms; se persistir, emita status=\u0027error\u0027 com code=\u0027E_MCP_TIMEOUT\u0027.\n- E_RAG_NO_MATCH (null ou score\u003c0.80): zero retry. Chame list_exams(limit=20), pegue o candidato mais proximo, marque inconclusive=true.\n- E_API_VALIDATION (422): 1 unico retry ajustando scheduled_for para hoje+7 dias; se persistir, emita status=\u0027error\u0027 com code=\u0027E_API_VALIDATION\u0027 e hint copiando o campo+motivo da resposta Pydantic.\n\nRESTRICOES:\n- NUNCA inclua nomes, CPFs ou telefones no JSON final. Use \u003cPERSON\u003e, \u003cCPF\u003e conforme recebidos.\n- patient_ref e SEMPRE anon-\u003chash\u003e. Nunca invente nomes reais.\n- Registre cada chamada de tool com params_hash e correlation_id para rastreabilidade.",
        tools=_tools,
        before_model_callback=make_pii_callback(allow_list=[]),
    )


# Module-level root_agent for `adk web` / `adk run` dev-server discovery.
# LAZY: built on first attribute access so `import <pkg>.agent` does not
# trigger a blocking httpx.get at import time.
def __getattr__(name: str) -> Any:
    if name == "root_agent":
        agent = _build_agent("boot")
        globals()["root_agent"] = agent
        return agent
    raise AttributeError(f"module {__name__!r} has no attribute {name!r}")
